import React from 'react';
import PropTypes from 'prop-types';
import { namespaceVisuallyHidden } from '../constants/namespaces';

/** @type {typeof import('../..').VisuallyHidden} */
const VisuallyHidden = ({ children, component: Component = 'span', ...other }) => (
  <Component className={namespaceVisuallyHidden} {...other}>{children}</Component>
);

VisuallyHidden.propTypes = {
  children: PropTypes.oneOfType([PropTypes.node, PropTypes.arrayOf(PropTypes.node)]).isRequired,
  component: PropTypes.oneOf(['div', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6', 'span']),
};

export default VisuallyHidden;
