import React from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { namespaceVisuallyHiddenFocusable } from '../constants/namespaces';

/** @type {typeof import('../..').VisuallyHiddenFocusable} */
const VisuallyHiddenFocusable = ({ children, component: Component = 'button', className, ...other }) => (
  <Component
    className={classNames(namespaceVisuallyHiddenFocusable, className)}
    {...other}
  >
    {children}
  </Component>
);

VisuallyHiddenFocusable.propTypes = {
  className: PropTypes.string,
  children: PropTypes.oneOfType([PropTypes.node, PropTypes.arrayOf(PropTypes.node)]),
  component: PropTypes.oneOf(['input', 'textarea', 'button', 'select', 'option', 'a', 'details', 'summary']),
};

export default VisuallyHiddenFocusable;
